<?php include 'header.php'; if(isset($_GET['remove'])){unset($_SESSION['cart'][intval($_GET['remove'])]); header('Location: cart.php'); exit;} $items=[]; $total=0; if(!empty($_SESSION['cart'])){$ids=array_keys($_SESSION['cart']); $ph=implode(',',array_fill(0,count($ids),'?')); $stmt=$pdo->prepare("SELECT * FROM products WHERE id IN ($ph)"); $stmt->execute($ids); $items=$stmt->fetchAll();} ?>
<section class="section"><h1>Your Cart</h1><?php if(!$items): ?><p>Your cart is empty.</p><?php else: ?><table><tr><th>Product</th><th>Qty</th><th>Price</th><th>Subtotal</th><th></th></tr><?php foreach($items as $item): $qty=$_SESSION['cart'][$item['id']]; $sub=$qty*$item['price']; $total+=$sub; ?><tr><td><?= htmlspecialchars($item['name']); ?></td><td><?= $qty; ?></td><td>$<?= number_format($item['price'],2); ?></td><td>$<?= number_format($sub,2); ?></td><td><a href="cart.php?remove=<?= $item['id']; ?>">Remove</a></td></tr><?php endforeach; ?></table><h2>Total: $<?= number_format($total,2); ?></h2><a class="btn" href="checkout.php">Checkout</a><?php endif; ?></section><?php include 'footer.php'; ?>
